import { useQuery } from '@tanstack/react-query';
import { api } from '../api/client';

export function Workspace({ matterId }: Props) {
  const { data: walkthrough } = useQuery(['walkthrough', matterId], () => api.walkthrough.get(matterId), { refetchOnWindowFocus: true });
  return <WorkspaceLayout data={walkthrough} />;
}

